  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


float z = q30;
float d = q31;
float pi = q28;
float pi2inv = q29;
float mask_apex = q32;
float zoom = q27;

vec2 c = zoom*(vUv-0.5)*uAspect.xy;

float camera_apex = atan( length(c),z);

bool mask = mask_apex >= camera_apex;

