factorB = vec2(q20,q21);
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y,factorA.x*factorB.y + factorA.y*factorB.x);
p.zy = product.xy;

factorA = p.zx;
factorB = vec2(q22,q23);
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y,factorA.x*factorB.y + factorA.y*factorB.x);
p.zx = product.xy;

factorA = p.yx;
factorB = vec2(q24,q25);
product = vec2( factorA.x*factorB.x - factorA.y*factorB.y, factorA.x*factorB.y + factorA.y*factorB.x);
p.yx = product.xy;
polar = vec2(atan(p.z,p.x),atan(p.y,length(p.xz)))*pi2inv*vec2(1,2)+vec2(0,0.5);

polar = polar;

    vec3 pos = vec3(polar,uTime*0.15);
    vec3 rc = texture3D(sampler_noisevol_hq, pos);
    rc += texture3D(sampler_noisevol_hq, 2*pos)*0.5;
    rc += texture3D(sampler_noisevol_hq, 4*pos)*0.25;
    rc += texture3D(sampler_noisevol_hq, 8*pos)*0.125;
    rc += texture3D(sampler_noisevol_hq, 16*pos)*0.0625;
    //rc = rc*0.556;
    rc = (rc*rc*rc)*2;
    //rc -= GetBlur1(vUv);
    rc *= q3*0.5;

    vec2 ruv = vUv = 0.5 + (vUv-0.5)*(1+(rc.x*.0));
    ret = texture(sampler_fc_main, vec2(ruv.x, ruv.y)).xyz;

